  // (ext i1 A) + (ext i1 B) != C --> logical op
  // where ext is zext or sext
  {
    Value *A, *B;
    const APInt *C;
    Instruction *ExtA, *ExtB;
    if (match(&I, m_c_ICmp(PredUnused,
                           m_c_Add(m_CombineAnd(m_Instruction(ExtA),
                                                m_ZExtOrSExt(m_Value(A))),
                                   m_CombineAnd(m_Instruction(ExtB),
                                                m_ZExtOrSExt(m_Value(B)))),
                           m_APInt(C))) &&
        A->getType()->isIntOrIntVectorTy(1)) {
      unsigned ExtAOpc = ExtA->getOpcode();
      unsigned ExtBOpc = ExtB->getOpcode();
      unsigned BW = C->getBitWidth();

      APInt ValA(BW, ExtAOpc == Instruction::SExt ? -1 : 1);
      APInt ValB(BW, ExtBOpc == Instruction::SExt ? -1 : 1);

      // Compute the four possible sums and their corresponding conditions.
      APInt Sum00 = APInt(BW, 0);
      APInt Sum01 = ValB;
      APInt Sum10 = ValA;
      APInt Sum11 = ValA + ValB;

      // For each sum value, the condition that produces it:
      auto GetCond = [&](const APInt &S) -> Value * {
        if (S == Sum00 && S == Sum11) {
          // Both (0,0) and (1,1) produce the same sum -> A == B
          return Builder.CreateXor(Builder.CreateNot(A), B);
        }
        if (S == Sum00 && S == Sum01) {
          // (0,0) and (0,1) -> !A
          return Builder.CreateNot(A);
        }
        if (S == Sum00 && S == Sum10) {
          // (0,0) and (1,0) -> !B
          return Builder.CreateNot(B);
        }
        if (S == Sum01 && S == Sum11) {
          // (0,1) and (1,1) -> B
          return B;
        }
        if (S == Sum10 && S == Sum11) {
          // (1,0) and (1,1) -> A
          return A;
        }
        // Exactly one truth table entry matches:
        if (S == Sum00)
          return Builder.CreateNot(Builder.CreateOr(A, B));
        if (S == Sum01)
          return Builder.CreateAnd(Builder.CreateNot(A), B);
        if (S == Sum10)
          return Builder.CreateAnd(A, Builder.CreateNot(B));
        if (S == Sum11)
          return Builder.CreateAnd(A, B);
        return nullptr;
      };

      Value *Cond = GetCond(*C);
      if (!Cond) {
        // C does not match any possible sum; eq is always false, ne is always true.
        return replaceInstUsesWith(I, Builder.getInt1(Pred != ICmpInst::ICMP_EQ));
      }
      if (Pred == ICmpInst::ICMP_NE)
        Cond = Builder.CreateNot(Cond);
      return replaceInstUsesWith(I, Cond);
    }
  }

  return nullptr;
