{"command": "cd /app/data/auto-opt/utils/llvm-64859 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 5204 5205

/// Fold icmp pred (add (ext i1 A), (ext i1 B)), C where ext is zext or sext.
/// The sum of two extended booleans can only take a few values, so we can
/// replace the comparison with a logical operation on the original booleans.
static Instruction *foldICmpAddOfBoolExt(ICmpInst &I,
                                         InstCombiner::BuilderTy &Builder) {
  ICmpInst::Predicate Pred = I.getPredicate();
  Value *A, *B;
  const APInt *C;
  Instruction *ExtA, *ExtB;
  if (!match(&I, m_c_ICmp(m_c_Add(m_CombineAnd(m_Instruction(ExtA),
                                               m_ZExtOrSExt(m_Value(A))),
                                   m_CombineAnd(m_Instruction(ExtB),
                                               m_ZExtOrSExt(m_Value(B)))),
                          m_APInt(C))) ||
      !A->getType()->isIntOrIntVectorTy(1))
    return nullptr;

  unsigned ExtAOpc = ExtA->getOpcode();
  unsigned ExtBOpc = ExtB->getOpcode();
  unsigned BW = C->getBitWidth();

  // The value of ext(i1) is either 0 (for false) or Val (for true).
  APInt ValA(BW, ExtAOpc == Instruction::SExt ? -1 : 1);
  APInt ValB(BW, ExtBOpc == Instruction::SExt ? -1 : 1);

  // Compute the four possible sums and collect which ones satisfy the predicate.
  struct {
